/* Kho câu hỏi: SINH HỌC — Year 9 (Exploring Science International, Pearson KS3) */
/* Nguồn: Bio-Year9-ExploringScience.md + Science-Year9-Glossary.md */
/* Field exam:true = thuộc phạm vi đề Chuyên Anh Đề Án (Plant processes, Ecosystems, Health, Control/exchange). */
window.QBANK = window.QBANK || [];

/* ===== CHAPTER 1: Variation ===== */
window.QBANK.push(
  { s:"Biology", topic:"1. Variation", sub:"Definitions", year:9, exam:false,
    q:`What name is given to the differences between organisms?`,
    a:`Variation`,
    e:`Variation = sự khác biệt giữa các sinh vật. Mọi sinh vật, kể cả anh chị em ruột, đều có nét khác nhau. Đây là từ khoá quan trọng của cả chương, em nhớ kỹ nhé!` },
  { s:"Biology", topic:"1. Variation", sub:"Definitions", year:9, exam:false,
    q:`What name is given to a feature of an organism, such as eye colour or height?`,
    a:`A characteristic`,
    e:`Characteristic = đặc điểm/tính trạng. Variation chính là sự khác nhau giữa các characteristics. Ví dụ: màu mắt, chiều cao, nhóm máu.` },
  { s:"Biology", topic:"1. Variation", sub:"Environmental variation", year:9, exam:false,
    q:`What name is given to variation that is caused by an organism's surroundings, such as scars or hairstyles?`,
    a:`Environmental variation`,
    e:`Environmental variation = biến dị do môi trường. Sẹo (scars) do vật sắc nhọn hoặc lửa, kiểu tóc do thời trang — đều là yếu tố môi trường, không di truyền cho con.` },
  { s:"Biology", topic:"1. Variation", sub:"Environmental variation", year:9, exam:false,
    q:`Name two examples of environmental variation in humans.`,
    a:`Scars and hairstyles`,
    e:`Scars (sẹo) và hairstyles (kiểu tóc) đều do môi trường gây ra, không nằm trong genes. Em sinh ra không mang sẵn sẹo — đó là dấu hiệu của environmental variation.` },
  { s:"Biology", topic:"1. Variation", sub:"Environmental factors", year:9, exam:false,
    q:`What name is given to physical environmental factors such as temperature and amount of light?`,
    a:`Abiotic factors`,
    e:`Abiotic factors = yếu tố vô sinh (a- nghĩa là "không", biotic = sống). Ví dụ: nhiệt độ, ánh sáng, gió, lượng mưa. Chúng không liên quan đến sinh vật sống.` },
  { s:"Biology", topic:"1. Variation", sub:"Environmental factors", year:9, exam:false,
    q:`What name is given to environmental factors that come from the activities of other organisms, such as competition or predation?`,
    a:`Biotic factors`,
    e:`Biotic factors = yếu tố hữu sinh. Đó là hoạt động của các sinh vật khác: cạnh tranh (competition), săn mồi (predation), bệnh truyền nhiễm. So với abiotic (vô sinh), biotic luôn liên quan đến sinh vật sống.` },
  { s:"Biology", topic:"1. Variation", sub:"Inherited variation", year:9, exam:false,
    q:`What name is given to variation in characteristics passed from parents to offspring, such as eye colour and blood group?`,
    a:`Inherited variation`,
    e:`Inherited variation = biến dị di truyền. Con nhận một hỗn hợp đặc điểm từ bố mẹ qua genes. Ví dụ: màu mắt, cằm lúm đồng tiền, nhóm máu.` },
  { s:"Biology", topic:"1. Variation", sub:"Inherited variation", year:9, exam:false,
    q:`What name is given to variation that is passed from parents to offspring through genes?`,
    a:`Inherited variation`,
    e:`Inherited variation = biến dị di truyền, được truyền từ bố mẹ qua genes. So sánh hai loại: inherited variation đến từ bố mẹ qua genes nên di truyền cho đời sau; environmental variation do môi trường tác động (như sẹo, kiểu tóc) nên KHÔNG di truyền. Chúng khác nhau ở nguồn gốc. Một số đặc điểm như chiều cao chịu ảnh hưởng của cả hai.` },
  { s:"Biology", topic:"1. Variation", sub:"Continuous variation", year:9, exam:false,
    q:`What name is given to variation that can take any value between two points, such as height?`,
    a:`Continuous variation`,
    e:`Continuous variation = biến dị liên tục. Chiều cao có thể là 150 cm, 150.4 cm, 151 cm... bất kỳ giá trị nào ở giữa. Khi vẽ biểu đồ thường cho hình "chuông" (normal distribution).` },
  { s:"Biology", topic:"1. Variation", sub:"Discontinuous variation", year:9, exam:false,
    q:`What name is given to variation that can only have a value from a limited set, such as blood group?`,
    a:`Discontinuous variation`,
    e:`Discontinuous variation = biến dị gián đoạn. Nhóm máu chỉ có A, B, AB hoặc O — không có giá trị "ở giữa". Cỡ giày cũng vậy. Vẽ biểu đồ thì các cột có khoảng trống giữa chúng.` },
  { s:"Biology", topic:"1. Variation", sub:"Continuous variation", year:9, exam:false,
    q:`What type of variation is shoe size: continuous or discontinuous?`,
    a:`Discontinuous variation`,
    e:`Cỡ giày là discontinuous variation. Lý do: cỡ giày chỉ sản xuất theo các số cố định như 38, 39, 40 — không có giá trị "ở giữa". Ngược lại, chiều dài bàn chân thật có thể là bất kỳ giá trị nào nên là continuous variation. Cùng một đặc điểm nhưng đo theo cách khác nhau cho ra loại variation khác nhau!` },
  { s:"Biology", topic:"1. Variation", sub:"Continuous variation", year:9, exam:false,
    q:`Name two examples of continuous inherited variation in humans.`,
    a:`Human height and skin colour`,
    e:`Height (chiều cao) và skin colour (màu da) đều biến đổi liên tục và do di truyền. Lưu ý: chúng cũng chịu ảnh hưởng của môi trường (ví dụ ăn uống đủ chất mới cao được).` },
  { s:"Biology", topic:"1. Variation", sub:"Discontinuous variation", year:9, exam:false,
    q:`Name two examples of discontinuous inherited variation in humans.`,
    a:`Blood group and having a dimpled chin`,
    e:`Blood group (nhóm máu A/B/AB/O) và dimpled chin (cằm lúm đồng tiền) là các đặc điểm chỉ có một số lựa chọn cố định, nên là discontinuous. Cỡ giày cũng được tính là discontinuous.` },
  { s:"Biology", topic:"1. Variation", sub:"Normal distribution", year:9, exam:false,
    q:`What name is given to the bell-shaped curve formed when continuous variation data is plotted?`,
    a:`Normal distribution`,
    e:`Normal distribution = phân bố chuẩn. Hầu hết cá thể có giá trị gần mức trung bình, ít cá thể rất cao hoặc rất thấp — tạo ra hình "quả chuông". Thường gặp ở đặc điểm continuous như chiều cao.` },
  { s:"Biology", topic:"1. Variation", sub:"Normal distribution", year:9, exam:false,
    q:`In a normal distribution curve, the mean is the same as which two other averages?`,
    a:`The mode and the median`,
    e:`Trong đường cong normal distribution, ba số trung bình trùng nhau: mean (trung bình cộng), mode (giá trị xuất hiện nhiều nhất) và median (giá trị ở giữa). Đỉnh chuông chính là cả ba.` },
  { s:"Biology", topic:"1. Variation", sub:"Classification", year:9, exam:false,
    q:`What name is given to the process of sorting organisms into groups?`,
    a:`Classification`,
    e:`Classification = phân loại. Đây là việc sắp xếp sinh vật vào các nhóm dựa trên đặc điểm chung. Nhóm nhỏ nhất một sinh vật được xếp vào là species (loài).` },
  { s:"Biology", topic:"1. Variation", sub:"Species", year:9, exam:false,
    q:`What name is given to a group of organisms that can reproduce together to produce fertile offspring?`,
    a:`A species`,
    e:`Species = loài. Định nghĩa chuẩn: nhóm sinh vật có thể sinh sản với nhau và tạo ra con cái cũng có khả năng sinh sản tiếp. Đây là nhóm phân loại nhỏ nhất.` },
  { s:"Biology", topic:"1. Variation", sub:"Classification", year:9, exam:false,
    q:`What name is given to the smallest group into which an organism is classified?`,
    a:`Its species`,
    e:`Species (loài) là nhóm phân loại nhỏ nhất. Các loài gần nhau thì cùng một genus (chi). Tên khoa học gồm hai phần: tên chi + tên loài.` },
  { s:"Biology", topic:"1. Variation", sub:"Classification", year:9, exam:false,
    q:`Scientists grew seeds from short seashore plants and tall island plants in a lab, and they all grew the same. What does this tell you about the plants?`,
    a:`They are the same species; the difference was environmental variation.`,
    e:`Khi trồng trong cùng điều kiện, chúng giống hệt nhau — chứng tỏ sự khác biệt ban đầu (cao/thấp) chỉ do môi trường, không phải di truyền. Vậy chúng là cùng một loài.` },
  { s:"Biology", topic:"1. Variation", sub:"Classification", year:9, exam:false,
    q:`What type of variation can make plants of the same species look very different from each other?`,
    a:`Environmental variation`,
    e:`Đáp án là environmental variation (biến dị do môi trường). Lý do nó gây khó cho việc phân loại: cùng một loài nhưng sống ở nơi khác nhau (đất tốt/xấu, nhiều/ít ánh sáng) có thể trông rất khác nhau, khiến ta tưởng nhầm là hai loài khác nhau. Vì vậy nhà khoa học phải trồng chúng trong cùng điều kiện để kiểm tra.` },
  { s:"Biology", topic:"1. Variation", sub:"Sexual reproduction", year:9, exam:false,
    q:`What does each child receive from its parents that makes brothers and sisters look different from each other?`,
    a:`A different mixture of genes`,
    e:`Mỗi đứa con nhận một tổ hợp (mixture) genes riêng từ bố mẹ. Lý do anh chị em ruột không giống hệt nhau: mỗi gamete (giao tử) mang thông tin di truyền hơi khác nhau — không có hai gamete giống hệt. Vì vậy mỗi đứa con nhận một tổ hợp genes khác nhau, dẫn đến variation giữa anh chị em.` },
  { s:"Biology", topic:"1. Variation", sub:"Applied", year:9, exam:false,
    q:`Lan has a scar on her knee from falling off her bicycle. Is this an example of inherited or environmental variation?`,
    a:`Environmental variation`,
    e:`Sẹo của Lan do tai nạn (yếu tố môi trường) gây ra, không nằm trong genes nên không di truyền cho con. Đây là environmental variation — một ví dụ kinh điển trong sách.` },
  { s:"Biology", topic:"1. Variation", sub:"Applied", year:9, exam:false,
    q:`Nam measures the heights of all 120 students in Year 9 and plots a graph. He gets a bell-shaped curve. What name is given to this curve?`,
    a:`A normal distribution`,
    e:`Chiều cao là continuous variation, nên khi vẽ số học sinh theo từng nhóm chiều cao, Nam sẽ thấy đa số ở giữa và ít em ở hai đầu — tạo hình quả chuông gọi là normal distribution.` },
  { s:"Biology", topic:"1. Variation", sub:"Applied", year:9, exam:false,
    q:`Mai and her identical twin sister are raised in different countries. Mai grows taller. Suggest why two genetically identical people can differ in height.`,
    a:`Environmental factors such as diet also affect height.`,
    e:`Dù chị em sinh đôi cùng trứng có genes giống hệt, chiều cao vẫn chịu ảnh hưởng của môi trường — đặc biệt là chế độ ăn (diet), nên height cũng là environmental variation. Đây cho thấy một đặc điểm có thể do cả genes và môi trường quyết định.` },
  { s:"Biology", topic:"1. Variation", sub:"Reasoning", year:9, exam:false,
    q:`Suggest one characteristic of tomatoes that is caused by both genetic information and environmental factors.`,
    a:`The size of the tomato fruit`,
    e:`Kích thước quả cà chua phụ thuộc cả vào giống (genes) lẫn điều kiện chăm sóc như nước, ánh sáng, phân bón (môi trường). Nhiều đặc điểm continuous đều là sự kết hợp của cả hai.` }
);

/* ===== CHAPTER 2: Genes and inheritance ===== */
window.QBANK.push(
  { s:"Biology", topic:"2. Genes and inheritance", sub:"DNA", year:9, exam:false,
    q:`What does DNA stand for?`,
    a:`Deoxyribonucleic acid`,
    e:`DNA là viết tắt của deoxyribonucleic acid. Đây là chất chứa thông tin di truyền (genetic information) trong tế bào. Em không cần nhớ cách viết khó này, nhưng nên biết DNA = "chất di truyền".` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"DNA", year:9, exam:false,
    q:`What name is given to the substance found in cells that contains genetic information?`,
    a:`DNA`,
    e:`DNA mang toàn bộ "bản hướng dẫn" để xây dựng và vận hành sinh vật. Nó nằm trong nhân (nucleus) của tế bào, bên trong các cấu trúc gọi là chromosomes.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"Chromosomes", year:9, exam:false,
    q:`What name is given to the structures inside the nucleus of a cell, each containing one long DNA molecule?`,
    a:`Chromosomes`,
    e:`Chromosomes = nhiễm sắc thể. Mỗi nhiễm sắc thể chứa một phân tử DNA cực dài cuộn lại. Chúng nằm trong nhân (nucleus) của tế bào.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"Genes", year:9, exam:false,
    q:`What name is given to a section of a DNA molecule that contains the instructions for a characteristic?`,
    a:`A gene`,
    e:`Gene = đoạn của phân tử DNA mang hướng dẫn cho một đặc điểm. Hãy hình dung DNA như một quyển sách dài, còn mỗi gene là một "chương" hướng dẫn về một tính trạng.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"Structure", year:9, exam:false,
    q:`Put these in order from largest to smallest: gene, nucleus, chromosome, DNA molecule.`,
    a:`Nucleus, chromosome, DNA molecule, gene`,
    e:`Nhân (nucleus) chứa các chromosomes; mỗi chromosome chứa một phân tử DNA; mỗi gene là một đoạn nhỏ của DNA. Thứ tự lồng vào nhau: nucleus > chromosome > DNA > gene.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"Genes", year:9, exam:false,
    q:`What do genes control?`,
    a:`Inherited characteristics`,
    e:`Genes điều khiển các đặc điểm di truyền (inherited characteristics). Một vài đặc điểm như nhóm máu ABO do một gene quyết định, nhưng phần lớn đặc điểm do nhiều genes cùng kiểm soát.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"Chromosome number", year:9, exam:false,
    q:`How many chromosomes are found in a normal human body cell?`,
    a:`46`,
    e:`Tế bào cơ thể người bình thường có 46 nhiễm sắc thể, xếp thành 23 cặp. Hai chiếc trong mỗi cặp mang cùng các genes và cùng kích thước (trừ cặp nhiễm sắc thể giới tính).` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"Chromosome number", year:9, exam:false,
    q:`How many chromosomes does a human gamete (sperm or egg cell) contain?`,
    a:`23`,
    e:`Gamete (giao tử: tinh trùng hoặc trứng) chỉ chứa 23 nhiễm sắc thể — bằng một nửa tế bào cơ thể. Khi hai gamete kết hợp, hợp tử có 23 + 23 = 46.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"Fertilisation", year:9, exam:false,
    q:`What name is given to the cell produced when a sperm cell and an egg cell fuse together?`,
    a:`A zygote`,
    e:`Zygote = hợp tử = tế bào trứng đã thụ tinh. Nó hình thành khi tinh trùng và trứng hợp nhất (fertilisation) và chứa 46 nhiễm sắc thể — 23 từ bố, 23 từ mẹ.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"Fertilisation", year:9, exam:false,
    q:`What name is given to the fusing of a male gamete with a female gamete?`,
    a:`Fertilisation`,
    e:`Fertilisation = sự thụ tinh. Đó là quá trình tinh trùng (giao tử đực) hợp nhất với trứng (giao tử cái) để tạo thành hợp tử. Đây là bước mở đầu của sinh sản hữu tính.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"Sex chromosomes", year:9, exam:false,
    q:`Which two sex chromosomes do human females have?`,
    a:`Two X chromosomes`,
    e:`Nữ giới có hai nhiễm sắc thể X (viết là XX), cả hai cùng kích thước. Nam giới có một X và một Y nhỏ hơn (XY). Cặp nhiễm sắc thể giới tính quyết định giới tính của cơ thể.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"Sex chromosomes", year:9, exam:false,
    q:`Which two sex chromosomes do human males have?`,
    a:`One X chromosome and one Y chromosome`,
    e:`Nam giới có một X và một Y (viết là XY). Nhiễm sắc thể Y nhỏ hơn X nhiều. Nữ giới là XX. Đây là cặp duy nhất trong 23 cặp mà hai chiếc có thể khác kích thước.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"Cell division", year:9, exam:false,
    q:`What name is given to the splitting of a parent cell to form two identical daughter cells?`,
    a:`Cell division`,
    e:`Cell division = sự phân chia tế bào. Sau khi hợp tử hình thành, nó phân chia liên tục tạo thành một khối tế bào. Mỗi tế bào con chứa bản sao giống hệt 46 nhiễm sắc thể.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"Cell division", year:9, exam:false,
    q:`What name is given to genetic information in the daughter cells that is exactly the same as in the parent cell?`,
    a:`Identical`,
    e:`Sau cell division, thông tin di truyền trong các tế bào con (daughter cells) là identical (giống hệt) với tế bào mẹ (parent cell). Lý do: cell division sao chép chính xác toàn bộ DNA trước khi chia, nên mỗi tế bào con nhận một bản sao y hệt 46 nhiễm sắc thể. Nhờ vậy mọi tế bào trong cơ thể em đều mang cùng một bộ genes.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"DNA structure", year:9, exam:false,
    q:`Which two scientists built the first model of the structure of DNA in 1953?`,
    a:`James Watson and Francis Crick`,
    e:`Watson và Crick đã dựng mô hình DNA bằng bìa cứng năm 1953. Họ dùng dữ liệu của chính mình và của các nhà khoa học khác để hoàn thành mô hình.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"DNA structure", year:9, exam:false,
    q:`Which scientist took X-ray photos of DNA that helped Watson and Crick work out its structure?`,
    a:`Rosalind Franklin`,
    e:`Rosalind Franklin (cùng Maurice Wilkins) chụp ảnh DNA bằng tia X. Bức ảnh hình chữ X mờ của bà cho thấy DNA là phân tử xoắn, giúp Watson và Crick hoàn thiện mô hình.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"DNA shape", year:9, exam:false,
    q:`What name is given to the spiral shape of a DNA molecule, made of two strands twisted together?`,
    a:`A double helix`,
    e:`Double helix = xoắn kép. DNA gồm hai sợi xoắn song song quanh nhau như cầu thang xoắn ốc. Watson nhận ra từ ảnh tia X rằng chỉ phân tử xoắn mới tạo ra hình chữ X.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"Genetic disorders", year:9, exam:false,
    q:`A genetic disorder is caused by a change in which substance inside a cell?`,
    a:`DNA`,
    e:`Rối loạn di truyền (genetic disorder) do một sai sót trong DNA — chất di truyền (genetic material) — làm thay đổi cách hoạt động của tế bào. Người sinh ra đã mang sẵn rối loạn này.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"Genetic disorders", year:9, exam:false,
    q:`What name is given to the specialist a couple can see to find out the chance of passing on a genetic disorder?`,
    a:`A genetic counsellor`,
    e:`Đáp án là genetic counsellor (chuyên gia tư vấn di truyền). Lý do một cặp đôi sắp lập gia đình tìm đến họ: genetic counsellor giúp tính ra xác suất con của họ có thể mang một rối loạn di truyền (genetic disorder). Biết được khả năng này giúp gia đình chuẩn bị tinh thần và đưa ra quyết định phù hợp.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"Probability", year:9, exam:false,
    q:`What is meant by the probability of an event?`,
    a:`The likelihood of that event happening.`,
    e:`Probability = xác suất = khả năng (likelihood/chance) một sự việc xảy ra. Nó thường được viết dưới dạng phần trăm, phân số hoặc số thập phân. Sự việc chắc chắn xảy ra có xác suất 100%.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"Probability", year:9, exam:false,
    q:`A coin is flipped 100 times and lands heads 52 times. What is the experimental probability of heads, as a percentage?`,
    a:`52%`,
    e:`Experimental probability = số lần xảy ra / tổng số lần thử. Ở đây 52/100 = 52%. Đây là xác suất thực nghiệm — dựa trên kết quả thí nghiệm thật, không phải lý thuyết.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"Probability", year:9, exam:false,
    q:`If one parent has achondroplasia, the probability of their child having it is 50%. Write this probability as a decimal.`,
    a:`0.5`,
    e:`Đổi phần trăm sang số thập phân: chia cho 100. 50% = 50/100 = 0.5. Xác suất cũng có thể viết dưới dạng phân số (1/2) — cả ba cách đều đúng.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"Probability scale", year:9, exam:false,
    q:`On a probability scale, what is the probability of an event that is certain to happen? Give your answer as a percentage.`,
    a:`100%`,
    e:`Sự việc chắc chắn xảy ra (như Mặt Trời mọc ngày mai) có xác suất 100%, hay viết dưới dạng số là 1. Sự việc không thể xảy ra có xác suất 0%. Cơ hội ngang nhau là 50%.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"Applied", year:9, exam:false,
    q:`Nam rolls one six-sided dice. What is the theoretical probability of rolling a '1', as a fraction?`,
    a:`1/6`,
    e:`Xúc xắc có 6 mặt, mỗi mặt có cơ hội ngang nhau, nên xác suất ra số 1 là 1/6. Xác suất "không ra số 1" là 5/6. Đây là theoretical probability — tính bằng lý thuyết.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"Applied", year:9, exam:false,
    q:`Lan learns that a woolly mammoth had 58 chromosomes in its body cells. How many chromosomes would a mammoth sperm cell contain?`,
    a:`29`,
    e:`Giao tử (sperm) chỉ chứa một nửa số nhiễm sắc thể của tế bào cơ thể. 58 ÷ 2 = 29. Khi tinh trùng kết hợp với trứng, hợp tử lại có đủ 58.` },
  { s:"Biology", topic:"2. Genes and inheritance", sub:"Applied", year:9, exam:false,
    q:`Mai is told a person has chromosomes XX. What sex is this person, and why?`,
    a:`Female, because she has two X sex chromosomes.`,
    e:`XX = nữ giới. Nam giới là XY (một X và một Y nhỏ hơn). Em chỉ cần nhìn cặp nhiễm sắc thể giới tính để biết: hai X là nữ, một X một Y là nam.` }
);

/* ===== CHAPTER 3: Evolution and natural selection ===== */
window.QBANK.push(
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Definitions", year:9, exam:false,
    q:`What does it mean when a type of organism is described as 'extinct'?`,
    a:`The organism no longer exists; there are none left alive.`,
    e:`Extinct = tuyệt chủng. Khi loài không còn cá thể nào sống sót, ta nói loài đó đã extinct. Ví dụ: khủng long, voi ma mút (woolly mammoth).` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Definitions", year:9, exam:false,
    q:`What word describes a type of organism that is in danger of ceasing to exist?`,
    a:`Endangered`,
    e:`Endangered = nguy cấp. Loài endangered đang có nguy cơ tuyệt chủng nhưng vẫn còn cá thể sống. Nếu không được bảo vệ, nó có thể trở thành extinct.` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Adaptations", year:9, exam:false,
    q:`What name is given to a feature that helps an organism survive in its habitat?`,
    a:`An adaptation`,
    e:`Adaptation = sự thích nghi. Đó là đặc điểm giúp sinh vật tồn tại trong môi trường sống. Ví dụ: tai to của voi giúp làm mát máu, lông dày của ma mút giúp chống lạnh.` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Adaptations", year:9, exam:false,
    q:`The adaptations of an organism are due to which part of the organism?`,
    a:`Its genes`,
    e:`Adaptations do genes quyết định. Vì vậy khi môi trường thay đổi, loài có thể không còn thích nghi tốt nữa và trở thành endangered hoặc extinct.` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Extinction", year:9, exam:false,
    q:`State one biotic factor that can cause a species to become extinct.`,
    a:`Competition from other organisms`,
    e:`Biotic factor (yếu tố hữu sinh) gây tuyệt chủng gồm: cạnh tranh, bệnh tật, hoạt động của con người (săn bắn, phá rừng, dùng thuốc độc) — nêu bất kỳ một ý nào cũng được. Ngược lại, abiotic factor là yếu tố vô sinh như lượng mưa.` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Competition", year:9, exam:false,
    q:`What name is given to the situation when organisms need the same resources and must fight for them?`,
    a:`Competition`,
    e:`Competition = cạnh tranh. Khi các sinh vật cùng cần một nguồn tài nguyên (thức ăn, ánh sáng, nước, không gian), chúng phải cạnh tranh. Sóc xám và sóc đỏ cạnh tranh thức ăn là ví dụ trong sách.` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Competition", year:9, exam:false,
    q:`Grey squirrels can digest unripe acorns but red squirrels cannot. Which squirrel gets less food as a result?`,
    a:`The red squirrel`,
    e:`Đáp án là sóc đỏ (red squirrel). Lý do: sóc xám tiêu hoá được hạt sồi xanh nên ăn được trước; sóc đỏ không tiêu hoá được hạt xanh nên phải đợi hạt chín, vì vậy còn ít thức ăn hơn. Sóc xám thích nghi tốt hơn (better adapted), số lượng tăng nhanh và outcompete (cạnh tranh thắng) sóc đỏ — đó là lý do sóc đỏ ngày càng thiếu ăn.` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Natural selection", year:9, exam:false,
    q:`What name is given to the process in which organisms with a useful inherited variation are more likely to survive and reproduce?`,
    a:`Natural selection`,
    e:`Natural selection = chọn lọc tự nhiên. Cá thể có biến dị di truyền có lợi sẽ sống sót và sinh sản nhiều hơn, truyền đặc điểm đó cho đời sau. Môi trường "chọn" những biến dị tốt.` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Natural selection", year:9, exam:false,
    q:`In Manchester, when buildings became covered in soot, which colour of peppered moth was harder for birds to spot?`,
    a:`Black (dark)`,
    e:`Đáp án là bướm màu đen (black/dark). Lý do bướm đen sống sót tốt hơn: khi bồ hóng nhà máy làm cây và tường đen đi, bướm đen hoà lẫn vào nền đen nên khó bị chim phát hiện và ít bị ăn hơn; bướm sáng màu lại nổi bật trên nền đen nên bị chim ăn nhiều. Đây là một ví dụ kinh điển của chọn lọc tự nhiên (natural selection).` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Natural selection", year:9, exam:false,
    q:`What did surviving black peppered moths pass on to their offspring, causing their numbers to increase?`,
    a:`The genes for black colour`,
    e:`Đáp án là genes quy định màu đen (the genes for black colour). Lý do số bướm đen tăng dần: bướm đen sống sót nhiều hơn (ít bị chim ăn) nên sinh sản nhiều hơn, truyền genes quy định màu đen cho con cái. Qua nhiều thế hệ, số bướm mang genes "màu đen" cứ tăng lên — đó chính là cách chọn lọc tự nhiên làm thay đổi quần thể.` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Evolution", year:9, exam:false,
    q:`What name is given to a change over time in the characteristics of a population of organisms?`,
    a:`Evolution`,
    e:`Evolution = tiến hoá = sự thay đổi các đặc điểm của một quần thể qua thời gian dài. Chọn lọc tự nhiên là nguyên nhân chính gây ra tiến hoá.` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Evolution", year:9, exam:false,
    q:`Which two scientists both developed the hypothesis that natural selection causes evolution?`,
    a:`Charles Darwin and Alfred Russel Wallace`,
    e:`Darwin và Wallace cùng đưa ra giả thuyết rằng chọn lọc tự nhiên gây ra tiến hoá. Ngày nay nó thường gọi là "thuyết tiến hoá của Darwin" (Darwin's theory of evolution).` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Salton Sea", year:9, exam:false,
    q:`The Salton Sea slowly became very salty. Which characteristic was 'naturally selected' in the tilapia fish that survived?`,
    a:`The ability to tolerate very salty water.`,
    e:`Khi biển mặn dần, những con tilapia tình cờ mang biến dị chịu mặn tốt (cope with/tolerate salty water) sống sót và sinh sản nhiều hơn. Qua nhiều thế hệ, mọi con tilapia ở Salton Sea đều chịu được nước rất mặn.` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Species formation", year:9, exam:false,
    q:`What can a population evolve into if natural selection happens over a very long time?`,
    a:`A new species`,
    e:`Theo Darwin, khi chọn lọc tự nhiên diễn ra đủ lâu, một quần thể có thể tiến hoá thành một loài mới (new species). Nhiều nhà khoa học tin rằng một số khủng long đã tiến hoá thành chim.` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Hypothesis", year:9, exam:false,
    q:`What name is given to an idea about how something works that can be tested using experiments?`,
    a:`A hypothesis`,
    e:`Hypothesis = giả thuyết. Đó là một ý tưởng có thể kiểm tra bằng thí nghiệm. Khi nhiều bằng chứng ủng hộ một giả thuyết, nó dần trở thành một theory (lý thuyết).` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Biodiversity", year:9, exam:false,
    q:`What name is given to the range of different species of organisms in an area?`,
    a:`Biodiversity`,
    e:`Biodiversity = đa dạng sinh học = số lượng các loài khác nhau trong một khu vực. Tuyệt chủng làm giảm biodiversity, vì vậy chúng ta cần bảo tồn nó.` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Conservation", year:9, exam:false,
    q:`Name two ways of preserving biodiversity.`,
    a:`Banning the hunting of certain animals and setting up nature reserves.`,
    e:`Để bảo tồn biodiversity ta có thể: cấm săn bắn một số loài, lập khu bảo tồn thiên nhiên, chạy chương trình nhân giống (breeding programmes), và lưu giữ hạt/giao tử trong gene banks — nêu bất kỳ hai ý nào.` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Gene banks", year:9, exam:false,
    q:`What name is given to a facility that stores genetic material such as seeds and gametes at low temperatures?`,
    a:`A gene bank`,
    e:`Gene bank = ngân hàng gene. Nơi này lưu trữ hạt giống, giao tử, mẫu mô ở nhiệt độ thấp. Nếu một loài tuyệt chủng ngoài tự nhiên, các vật liệu này có thể dùng để tạo lại loài đó.` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Gene banks", year:9, exam:false,
    q:`What does a gene bank store that can be used to grow a plant species again if it becomes extinct in the wild?`,
    a:`Seeds (or gametes)`,
    e:`Đáp án là hạt giống (seeds) — gene bank cũng lưu giao tử (gametes). Lý do gene bank giúp loài sống sót: nó giữ hạt và giao tử ở nhiệt độ thấp; nếu cây tuyệt chủng ngoài tự nhiên, người ta vẫn có thể gieo hạt đã lưu trữ để tái tạo loài. Gene bank hoạt động như một "bản sao lưu" của sự sống.` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Reasoning", year:9, exam:false,
    q:`Predict one effect of global warming on the population of polar bears, and explain your reasoning.`,
    a:`The population may fall, because melting ice reduces their habitat and food.`,
    e:`Gấu Bắc Cực thích nghi với băng tuyết. Khi Trái Đất nóng lên, băng tan, môi trường sống (habitat) và nguồn thức ăn để săn mồi thu hẹp lại — chúng không còn thích nghi tốt nên số lượng có thể giảm.` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Mammoths", year:9, exam:false,
    q:`Many scientists think woolly mammoths and elephants evolved from one species. Give one adaptation that helped mammoths survive in cold conditions.`,
    a:`A thick covering of hair`,
    e:`Ma mút tiến hoá để chịu lạnh: lông dày, hoặc cơ thể lớn (vật lớn mất nhiệt chậm hơn) — nêu một ý là đủ. Voi thì tiến hoá để chịu nóng, ví dụ tai to để làm mát máu.` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Applied", year:9, exam:false,
    q:`What has happened to a dinosaur's DNA after 65 million years, making it impossible to clone?`,
    a:`It has decomposed.`,
    e:`Đáp án: DNA của khủng long đã phân huỷ hết (it has decomposed). Lý do không thể nhân bản khủng long: DNA của ma mút còn giữ được trong xác đông lạnh (chỉ khoảng 4000 năm), nhưng khủng long tuyệt chủng 65 triệu năm trước nên DNA của chúng đã phân huỷ (decomposed) hoàn toàn — không còn vật chất di truyền nguyên vẹn để dùng cho cloning (nhân bản).` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Applied", year:9, exam:false,
    q:`Squirrel pox is a disease that does not affect grey squirrels but kills red squirrels. Is this a biotic or an abiotic factor?`,
    a:`A biotic factor`,
    e:`Bệnh tật là biotic factor (yếu tố hữu sinh) vì do vi sinh vật sống gây ra. Sóc xám mang bệnh nhưng không bị ảnh hưởng, còn sóc đỏ thì chết — một lợi thế nữa của sóc xám.` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Applied", year:9, exam:false,
    q:`Lan reads that grey squirrels store more fat than red squirrels. What does this stored fat provide during a long, cold winter?`,
    a:`Energy`,
    e:`Đáp án là năng lượng (energy). Lý do mỡ dự trữ giúp sóc xám sống sót: vào mùa đông dài, thức ăn khan hiếm (scarce), nên mỡ dự trữ trở thành nguồn năng lượng để sóc duy trì sự sống. Sóc xám trữ nhiều mỡ hơn nên sống sót tốt hơn — đây là một biến dị di truyền có lợi, được chọn lọc tự nhiên ưu ái.` },
  { s:"Biology", topic:"3. Evolution and natural selection", sub:"Reasoning", year:9, exam:false,
    q:`When two separated populations have evolved so much that they can no longer reproduce together, what have they become?`,
    a:`Two new species`,
    e:`Đáp án: chúng đã trở thành hai loài mới (two new species). Cách natural selection tạo ra loài mới: khi hai quần thể của cùng một loài bị tách ra (ví dụ bởi núi hay biển), mỗi nhóm chịu chọn lọc tự nhiên khác nhau và tiến hoá theo hướng riêng, phát triển các characteristics khác nhau. Sau rất nhiều thế hệ, chúng khác đến mức không còn sinh sản với nhau được nữa — theo định nghĩa species, lúc đó chúng đã là hai loài riêng biệt.` }
);

/* ===== CHAPTER 4: Plant processes ===== */
const BIX_PHOTO = { title:`Photosynthesis in a leaf`, html:`<p>Green plants make their own food in a process called photosynthesis. Inside the leaf cells are tiny green discs called chloroplasts, which contain a green pigment that traps light energy. The plant uses this energy to combine carbon dioxide from the air with water from the soil, producing a sugar called glucose. Oxygen is released as a waste product. The rate of photosynthesis can be slowed down by a limiting factor, such as low light, a shortage of carbon dioxide, or a low temperature.</p><p><i>[Figure: a cross-section of a leaf. Carbon dioxide arrows enter through small pores on the underside; water arrows rise up from the roots through tube-like vessels; an oxygen arrow leaves the leaf; a sun symbol shines light onto the upper surface where the green pigment is concentrated.]</i></p>` };

window.QBANK.push(
  { s:"Biology", topic:"4. Plant processes", sub:"Photosynthesis", year:9, exam:true,
    q:`What name is given to the process that plants use to make their own food using light energy?`,
    a:`Photosynthesis`,
    e:`Photosynthesis = quang hợp. Đây là quá trình cây tự tạo thức ăn (glucose) bằng năng lượng ánh sáng. "Photo" = ánh sáng, "synthesis" = tổng hợp.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Photosynthesis", year:9, exam:true,
    q:`Write the word equation for photosynthesis.`,
    a:`carbon dioxide + water → glucose + oxygen`,
    e:`Phương trình quang hợp bằng lời: carbon dioxide + nước → glucose + oxygen. Nguyên liệu (reactants) ở bên trái, sản phẩm (products) ở bên phải. Cần ánh sáng để phản ứng xảy ra.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Photosynthesis", year:9, exam:true,
    q:`Write the symbol equation for photosynthesis.`,
    a:`6CO₂ + 6H₂O → C₆H₁₂O₆ + 6O₂`,
    e:`Phương trình quang hợp bằng ký hiệu: 6CO₂ + 6H₂O → C₆H₁₂O₆ + 6O₂. C₆H₁₂O₆ là glucose. Số nguyên tử mỗi loại bằng nhau ở hai vế (phương trình cân bằng).` },
  { s:"Biology", topic:"4. Plant processes", sub:"Photosynthesis", year:9, exam:true,
    q:`Name the two reactants (raw materials) needed for photosynthesis.`,
    a:`Carbon dioxide and water`,
    e:`Hai nguyên liệu cho quang hợp là carbon dioxide (CO₂ từ không khí) và water (nước từ đất qua rễ). Sản phẩm là glucose và oxygen.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Photosynthesis", year:9, exam:true,
    q:`Name the two products of photosynthesis.`,
    a:`Glucose and oxygen`,
    e:`Quang hợp tạo ra glucose (một loại đường, thức ăn của cây) và oxygen (thải ra không khí). Oxygen này chính là khí mà con người và động vật cần để thở.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Chlorophyll", year:9, exam:true,
    q:`What name is given to the green substance in plants that traps light energy?`,
    a:`Chlorophyll`,
    e:`Chlorophyll = diệp lục. Đây là chất màu xanh hấp thụ năng lượng ánh sáng cho quang hợp. Nó nằm bên trong các chloroplasts trong tế bào cây.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Chloroplasts", year:9, exam:true,
    q:`In which part of a plant cell does photosynthesis take place?`,
    a:`In the chloroplasts`,
    e:`Photosynthesis diễn ra trong chloroplasts — các đĩa nhỏ màu xanh chứa chlorophyll. Tế bào palisade trong lá có rất nhiều chloroplasts để bắt ánh sáng hiệu quả.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Limiting factors", year:9, exam:true,
    q:`What name is given to a variable that prevents the rate of photosynthesis from getting any faster?`,
    a:`A limiting factor`,
    e:`Limiting factor = yếu tố giới hạn. Đó là biến số làm chậm tốc độ quang hợp khi nó thiếu hụt. Ví dụ: ánh sáng yếu, thiếu CO₂ hoặc nhiệt độ thấp.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Limiting factors", year:9, exam:true,
    q:`Name three factors that can limit the rate of photosynthesis.`,
    a:`Amount of light, amount of carbon dioxide, and temperature.`,
    e:`Ba yếu tố giới hạn quang hợp: lượng ánh sáng, lượng carbon dioxide, và nhiệt độ. Nếu một trong số chúng thiếu, quang hợp sẽ chậm lại dù các yếu tố khác đầy đủ.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Photosynthesis", year:9, exam:true,
    q:`What does a plant need from its surroundings to photosynthesise, which is only available during the day?`,
    a:`Light energy`,
    e:`Đáp án là năng lượng ánh sáng (light energy). Lý do cây chỉ quang hợp ban ngày: photosynthesis cần năng lượng ánh sáng để xảy ra; ban đêm không có ánh sáng nên cây không thể quang hợp. Tuy nhiên cây vẫn hô hấp (respiration) suốt cả ngày lẫn đêm vì hô hấp không cần ánh sáng.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Respiration", year:9, exam:true,
    q:`Write the word equation for aerobic respiration.`,
    a:`glucose + oxygen → carbon dioxide + water`,
    e:`Hô hấp hiếu khí: glucose + oxygen → carbon dioxide + water (+ năng lượng). Đây là quá trình ngược với quang hợp — nó giải phóng năng lượng dự trữ trong glucose.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Respiration", year:9, exam:true,
    q:`What is the purpose of aerobic respiration in a plant cell?`,
    a:`To release the energy stored in glucose.`,
    e:`Aerobic respiration giải phóng năng lượng từ glucose. Cây cần năng lượng này để lớn lên và tạo ra các chất mới. Mọi tế bào sống đều hô hấp.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Respiration", year:9, exam:true,
    q:`During the day, which process makes the extra oxygen that a plant gives off?`,
    a:`Photosynthesis`,
    e:`Đáp án là quang hợp (photosynthesis). Lý do cây thải oxygen ban ngày nhưng không thải ban đêm: ban ngày cây vừa quang hợp vừa hô hấp, mà quang hợp tạo oxygen nhiều hơn lượng hô hấp dùng, nên có oxygen dư thừa được thải ra. Ban đêm không có ánh sáng nên không quang hợp, cây chỉ hô hấp — không có oxygen dư để thải ra.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Transport", year:9, exam:true,
    q:`Which type of plant vessel carries water and dissolved mineral salts from the roots to the leaves?`,
    a:`Xylem vessels`,
    e:`Xylem = mạch gỗ, vận chuyển nước và muối khoáng từ rễ lên lá. Ống xylem hình thành khi các tế bào xylem chết đi và rỗng ruột. Mẹo nhớ: Xylem chở Water.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Transport", year:9, exam:true,
    q:`Which type of plant vessel carries dissolved sugars around the plant?`,
    a:`Phloem vessels`,
    e:`Phloem = mạch rây, vận chuyển đường (sugars) hoà tan đi khắp cây, kể cả xuống rễ. Phloem làm từ các tế bào sống. Mẹo: PHloem chở Food (đường).` },
  { s:"Biology", topic:"4. Plant processes", sub:"Roots", year:9, exam:true,
    q:`What feature do root hair cells have that makes them well adapted for absorbing water?`,
    a:`A large surface area`,
    e:`Đáp án: một bề mặt lớn (a large surface area). Cách root hair cell thích nghi với chức năng hút nước: mỗi tế bào lông hút có một sợi nhô dài ra, tạo diện tích bề mặt lớn để hút nước nhanh từ đất. Rễ cũng phân nhánh và lan rộng để lấy nước từ một vùng đất lớn.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Leaves", year:9, exam:true,
    q:`What name is given to the small holes in a leaf through which gases can diffuse in and out?`,
    a:`Stomata`,
    e:`Stomata (số ít: stoma) = khí khổng = các lỗ nhỏ trên lá. Khí như CO₂ và O₂ đi vào/ra qua đó bằng khuếch tán. Chúng được mở và đóng bởi các tế bào bảo vệ (guard cells).` },
  { s:"Biology", topic:"4. Plant processes", sub:"Leaves", year:9, exam:true,
    q:`Which cells open and close the stomata in a leaf?`,
    a:`Guard cells`,
    e:`Guard cells = tế bào bảo vệ. Chúng tạo thành một cặp ở mỗi khí khổng và điều khiển việc mở/đóng. Khí khổng thường mở ban ngày và đóng ban đêm.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Leaves", year:9, exam:true,
    q:`What do palisade cells contain large numbers of, making them well adapted for photosynthesis?`,
    a:`Chloroplasts`,
    e:`Đáp án là chloroplasts (lục lạp). Cách palisade cell thích nghi với quang hợp: tế bào palisade nằm gần mặt trên của lá và chứa rất nhiều chloroplasts, nên hấp thụ được nhiều ánh sáng và quang hợp mạnh. Đây là ví dụ kinh điển về cấu trúc thích nghi với chức năng (structure adapted to function).` },
  { s:"Biology", topic:"4. Plant processes", sub:"Leaves", year:9, exam:true,
    q:`Being broad and flat gives a leaf a large surface area for absorbing what?`,
    a:`Light`,
    e:`Đáp án là ánh sáng (light). Lý do lá nhiều cây có hình rộng và phẳng: hình dạng này tạo diện tích bề mặt lớn để bắt (trap/absorb) được nhiều ánh sáng cho quang hợp. Lá cũng mỏng nên CO₂ không phải khuếch tán xa mới tới được mọi tế bào.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Wilting", year:9, exam:true,
    q:`What name is given to a plant drooping because it has too little water?`,
    a:`Wilting`,
    e:`Wilting = héo. Khi thiếu nước, các tế bào xẹp xuống (không còn căng), khiến cây rũ xuống. Nước giữ cho tế bào căng và cứng, giúp cây đứng vững.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Plant substances", year:9, exam:true,
    q:`Glucose from photosynthesis can be linked together to form which storage polymer in plants?`,
    a:`Starch`,
    e:`Starch = tinh bột. Các phân tử glucose nối lại thành polymer này để dự trữ. Tinh bột không tan, được giữ trong lục lạp hoặc cơ quan dự trữ như củ khoai tây.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Food tests", year:9, exam:true,
    q:`Which solution is used to test for starch, and what colour change shows starch is present?`,
    a:`Iodine solution; it turns blue-black.`,
    e:`Để kiểm tra tinh bột, ta dùng dung dịch iodine. Nếu có tinh bột, màu chuyển từ nâu cam sang xanh đen (blue-black). Đây là một thí nghiệm hay gặp trong phòng lab.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Plant substances", year:9, exam:true,
    q:`Plant proteins are long chains of which smaller molecules?`,
    a:`Amino acids`,
    e:`Proteins là polymer gồm các chuỗi dài amino acids. Để tạo amino acids, cây cần nguồn nitrogen từ muối khoáng gọi là nitrates. Tất cả enzyme đều là protein.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Mineral salts", year:9, exam:true,
    q:`Which mineral salt do plants need to make proteins?`,
    a:`Nitrate`,
    e:`Nitrate cung cấp nitrogen — nguyên tố cần để tạo amino acids và protein. Nếu đất thiếu nitrate, cây không tạo đủ protein nên phát triển kém. Magnesium thì cần để tạo chlorophyll.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Germination", year:9, exam:true,
    q:`What name is given to the process when a seed starts to grow?`,
    a:`Germination`,
    e:`Germination = sự nảy mầm. Hạt bắt đầu mọc khi có nước, oxygen và đủ ấm. Hạt chứa sẵn kho dự trữ (tinh bột, protein) để nuôi cây con cho đến khi lá mở ra quang hợp được.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Applied", year:9, exam:true,
    q:`Mai puts pondweed in bright light and counts more oxygen bubbles than in dim light. What has happened to the rate of photosynthesis?`,
    a:`It has increased.`,
    e:`Đáp án: tốc độ quang hợp đã tăng lên (it has increased). Lý do Mai đếm được nhiều bọt oxygen hơn: ánh sáng càng mạnh thì tốc độ quang hợp càng nhanh, nên rong tạo ra nhiều oxygen hơn trong cùng một khoảng thời gian. Ánh sáng là một limiting factor (yếu tố giới hạn) — khi tăng nó, quang hợp tăng theo.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Applied", year:9, exam:true,
    q:`Nam's potted plant droops after he forgets to water it for a week. What name is given to this process?`,
    a:`Wilting`,
    e:`Đáp án là wilting (sự héo). Lý do cây của Nam rũ xuống: khi thiếu nước, các tế bào mất nước và xẹp xuống (sag), không còn căng cứng nữa nên không giữ được cây đứng thẳng — cây rũ xuống. Tưới nước kịp thời sẽ giúp tế bào căng trở lại và cây đứng thẳng lên.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Passage", year:9, exam:true, p:BIX_PHOTO,
    q:`Using the passage and the figure, name the green pigment that traps the light energy, and name the part of the cell that contains it.`,
    a:`Chlorophyll; it is contained in the chloroplasts.`,
    e:`Đoạn văn nói "a green pigment that traps light energy" — đó là chlorophyll (diệp lục). Nó nằm trong chloroplasts (lục lạp). Đề thi thường hỏi gắn passage với knowledge: read carefully để lấy đúng từ khoá.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Passage", year:9, exam:true, p:BIX_PHOTO,
    q:`Using the figure, the carbon dioxide enters the leaf through small pores on the underside. What name is given to these pores?`,
    a:`Stomata`,
    e:`Các lỗ nhỏ ở mặt dưới lá cho khí ra vào là stomata (khí khổng). CO₂ khuếch tán vào qua stomata, còn O₂ khuếch tán ra. Hình minh hoạ chỉ rõ mũi tên CO₂ đi vào qua các pores này.` },
  { s:"Biology", topic:"4. Plant processes", sub:"Passage", year:9, exam:true, p:BIX_PHOTO,
    q:`The passage says photosynthesis can be slowed by a limiting factor. On a cloudy, dim morning, which limiting factor is most likely to be reducing the rate?`,
    a:`Light`,
    e:`Sáng sớm trời nhiều mây thì ánh sáng yếu, nên light (lượng ánh sáng) là limiting factor làm chậm quang hợp. Đoạn văn liệt kê ba yếu tố: light thấp, thiếu CO₂, nhiệt độ thấp — ở đây ánh sáng là nguyên nhân rõ nhất.` }
);

/* ===== CHAPTER 5: Farming and ecosystems ===== */
const BIX_FOODWEB = { title:`Food webs and energy transfer`, html:`<p>A food web is made of many food chains linked together, and it shows how energy is transferred between organisms in a habitat. Every food chain begins with a producer, usually a green plant, which makes its own food by photosynthesis. Animals that eat plants are called primary consumers, and animals that eat other animals are called secondary or top consumers. Energy is passed along each chain, but only about 10 percent moves to the next level because the rest is lost as heat and movement.</p><p><i>[Figure: a pond food web. Grass and pondweed are drawn at the bottom as producers. Arrows lead from grass to a grasshopper and to a mouse. An arrow leads from the grasshopper to a frog, and from the mouse to an owl and to a snake. An arrow leads from the frog to the snake. The owl and the snake are at the top with no arrows leaving them.]</i></p>` };

window.QBANK.push(
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Definitions", year:9, exam:true,
    q:`What name is given to all the physical environmental factors and all the organisms found in a habitat?`,
    a:`An ecosystem`,
    e:`Ecosystem = hệ sinh thái. Nó gồm tất cả các yếu tố vô sinh (nhiệt độ, ánh sáng...) và tất cả các sinh vật sống trong một nơi ở (habitat).` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Definitions", year:9, exam:true,
    q:`What name is given to the place where an organism lives, for example woodland?`,
    a:`A habitat`,
    e:`Habitat = nơi ở = nơi một sinh vật sinh sống. Ví dụ: rừng cây, ao hồ, bãi đá ven biển. Đừng nhầm habitat (nơi ở) với ecosystem (cả hệ sinh thái).` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Food webs", year:9, exam:true,
    q:`What name is given to many food chains linked together, showing the flow of energy through organisms in a habitat?`,
    a:`A food web`,
    e:`Food web = lưới thức ăn. Nó gồm nhiều food chains (chuỗi thức ăn) nối với nhau, cho thấy năng lượng truyền qua các sinh vật trong một nơi ở.` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Food chains", year:9, exam:true,
    q:`What name is given to an organism, usually a green plant, that makes its own food at the start of a food chain?`,
    a:`A producer`,
    e:`Producer = sinh vật sản xuất. Đó thường là cây xanh, dùng quang hợp để tự tạo thức ăn. Mọi food chain đều bắt đầu từ một producer.` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Decomposers", year:9, exam:true,
    q:`What name is given to an organism that feeds on dead organisms or animal waste, causing them to decay?`,
    a:`A decomposer`,
    e:`Decomposer = sinh vật phân huỷ, ví dụ nấm và vi khuẩn. Chúng phân huỷ xác chết và phân động vật, trả lại chất dinh dưỡng cho đất để cây dùng lại.` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Carbon cycle", year:9, exam:true,
    q:`Which process removes carbon dioxide from the atmosphere?`,
    a:`Photosynthesis`,
    e:`Quang hợp lấy CO₂ ra khỏi không khí và "khoá" carbon vào trong cây. Đây là bước quan trọng trong carbon cycle (chu trình carbon).` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Carbon cycle", year:9, exam:true,
    q:`Name two processes that release carbon dioxide back into the atmosphere.`,
    a:`Respiration and combustion`,
    e:`Hai quá trình trả CO₂ về không khí: respiration (hô hấp của sinh vật) và combustion (sự cháy/burning, ví dụ đốt nhiên liệu hoá thạch). Chúng cân bằng với quang hợp trong carbon cycle.` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Carbon cycle", year:9, exam:true,
    q:`What name is given to the model that shows how carbon compounds are recycled in an ecosystem?`,
    a:`The carbon cycle`,
    e:`Carbon cycle = chu trình carbon. Đây là một mô hình cho thấy carbon được tái sử dụng liên tục: quang hợp lấy CO₂ vào, còn hô hấp và sự cháy thải CO₂ ra.` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Fertilisers", year:9, exam:true,
    q:`What do fertilisers contain that helps plants to grow?`,
    a:`Mineral salts, such as nitrates, phosphates and potassium.`,
    e:`Phân bón (fertilisers) chứa muối khoáng như nitrate, phosphate và potassium. Cây cần các muối này để khoẻ mạnh — ví dụ nitrate để tạo protein.` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Pesticides", year:9, exam:true,
    q:`What name is given to a chemical substance that kills pests (organisms that damage crops)?`,
    a:`A pesticide`,
    e:`Pesticide = thuốc trừ sâu/hại. Pest là sinh vật gây hại cho cây trồng. Có ba loại: insecticide (diệt côn trùng), fungicide (diệt nấm), herbicide (diệt cỏ dại).` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Pesticides", year:9, exam:true,
    q:`What name is given to a pesticide that kills weeds?`,
    a:`A herbicide`,
    e:`Herbicide (còn gọi là weedkiller) = thuốc diệt cỏ. Cỏ dại (weeds) cạnh tranh với cây trồng để giành nước, ánh sáng và muối khoáng, làm giảm năng suất. Herbicide hiện đại thường có tính chọn lọc.` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Pesticides", year:9, exam:true,
    q:`What name is given to a pesticide that kills insect pests?`,
    a:`An insecticide`,
    e:`Insecticide = thuốc diệt côn trùng. Nó tiêu diệt sâu bọ gây hại cây trồng. Tuy nhiên nó cũng có thể giết cả côn trùng có ích như ong thụ phấn.` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Yield", year:9, exam:true,
    q:`What is meant by the yield of a crop?`,
    a:`The amount of useful product obtained from a crop.`,
    e:`Yield = năng suất = lượng sản phẩm có ích thu được từ cây trồng. Nông dân muốn yield cao, nên họ dùng phân bón, thuốc trừ hại và chọn giống tốt.` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Eutrophication", year:9, exam:true,
    q:`What name is given to the process when a body of water contains excessive levels of nutrients, such as nitrates from fertilisers?`,
    a:`Eutrophication`,
    e:`Eutrophication = phú dưỡng. Khi phân bón trôi xuống sông hồ, nước quá giàu chất dinh dưỡng, làm tảo và cây mọc bùng phát rồi chết — gây thiếu oxygen và cá chết.` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Eutrophication", year:9, exam:true,
    q:`When fertilisers wash into a lake, what happens to the level of oxygen in the water?`,
    a:`It decreases.`,
    e:`Đáp án: lượng oxygen trong nước giảm xuống (it decreases). Lý do cá chết khi phân bón trôi vào hồ: phân bón làm tảo (algae) mọc bùng phát rồi chết hàng loạt; vi khuẩn phân huỷ (decomposer bacteria) phân giải xác tảo và trong quá trình hô hấp dùng hết oxygen hoà tan trong nước. Khi oxygen cạn, cá không còn khí để thở nên chết — đây là tác hại của eutrophication (phú dưỡng).` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Selective breeding", year:9, exam:true,
    q:`What name is given to the process when humans choose organisms with a certain characteristic and breed more of them?`,
    a:`Selective breeding`,
    e:`Selective breeding = chọn giống. Con người chỉ cho những cá thể mang đặc điểm mong muốn sinh sản. Lặp lại qua nhiều thế hệ, đặc điểm đó ngày càng rõ rệt — ví dụ tạo giống lúa mì thấp cây.` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Varieties", year:9, exam:true,
    q:`What name is given to a group of plants of the same species that has different characteristics from other plants of that species?`,
    a:`A variety`,
    e:`Variety = giống. Đó là một nhóm cây cùng loài nhưng được lai tạo để có đặc điểm riêng — ví dụ giống lúa mì kháng bệnh tốt hơn giống cũ.` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Organic farming", year:9, exam:true,
    q:`What name is given to producing food without using lots of artificial chemical substances?`,
    a:`Organic farming`,
    e:`Organic farming = canh tác hữu cơ. Nông dân chỉ dùng phân tự nhiên (như phân chuồng) và rất ít thuốc trừ hại tự nhiên. Họ cũng luân canh cây trồng và dùng biện pháp sinh học.` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Organic farming", year:9, exam:true,
    q:`In organic farming, what name is given to the use of living organisms to reduce the numbers of pest organisms?`,
    a:`Biological control`,
    e:`Biological control = kiểm soát sinh học. Thay vì phun thuốc, nông dân dùng sinh vật khác để diệt sâu hại — ví dụ thả ấu trùng ruồi giấm (hoverfly) để ăn rệp (aphids).` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Organic farming", year:9, exam:true,
    q:`State one advantage of organic farming compared with conventional farming.`,
    a:`Organic farms have greater biodiversity.`,
    e:`Ưu điểm của canh tác hữu cơ: đa dạng sinh học cao hơn. Nhược điểm: cần nhiều diện tích hơn để cho cùng lượng thực phẩm, và sản phẩm thường đắt hơn.` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Sustainable development", year:9, exam:true,
    q:`What name is given to developing the things humans need without destroying habitats and ecosystems?`,
    a:`Sustainable development`,
    e:`Sustainable development = phát triển bền vững. Đó là cách đáp ứng nhu cầu con người (thức ăn, năng lượng, nhà cửa) mà không phá huỷ môi trường sống của các loài khác.` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Bias", year:9, exam:true,
    q:`What is meant by bias in science?`,
    a:`A shift away from a true meaning or value.`,
    e:`Bias = thiên lệch. Đó là sự lệch khỏi giá trị thật. Bias có thể cố ý (chỉ chọn số liệu ủng hộ ý mình) hoặc vô tình (do sai số hệ thống hoặc lấy mẫu không ngẫu nhiên).` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Validity", year:9, exam:true,
    q:`What does it mean if a result or conclusion is valid?`,
    a:`It correctly measures or shows what it was supposed to.`,
    e:`Valid = hợp lệ/đáng tin. Kết quả hợp lệ khi nó đo đúng điều cần đo. Một thí nghiệm công bằng (fair test) cho kết quả valid vì chỉ có biến độc lập thay đổi.` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Reasoning", year:9, exam:true,
    q:`An insecticide can harm helpful insects such as bees. Which group of organisms does an insecticide kill?`,
    a:`Insects`,
    e:`Đáp án: insecticide diệt côn trùng nói chung (insects). Lý do nó hại cả côn trùng có ích: thuốc diệt côn trùng không phân biệt được sâu hại với côn trùng có ích — nó giết mọi loại côn trùng, kể cả ong thụ phấn (helpful insects như bees). Đó là lý do EU đã cấm một số thuốc neonicotinoid trên cây có hoa.` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Applied", year:9, exam:true,
    q:`A farmer plants only one variety of rice across a whole field. In their genes, how do all the plants compare with one another?`,
    a:`They are identical.`,
    e:`Đáp án: mọi cây giống hệt nhau (they are identical) về genes. Lý do trồng một giống duy nhất là rủi ro: vì các cây có cùng bộ genes, nếu một bệnh mới xuất hiện thì cả ruộng đều dễ mắc như nhau và có thể mất trắng. Một ruộng đa dạng hơn sẽ có vài cây kháng bệnh sống sót — như bài học từ nạn đói khoai tây ở Ireland thế kỷ 19.` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Applied", year:9, exam:true,
    q:`Lan's family grows vegetables and adds manure to the soil. Which microorganisms break down the manure to release mineral salts?`,
    a:`Decomposers`,
    e:`Phân chuồng (manure) được decomposers (vi sinh vật phân huỷ) phân giải, giải phóng muối khoáng cho cây hấp thụ. Quá trình này diễn ra chậm hơn so với phân bón nhân tạo.` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Passage", year:9, exam:true, p:BIX_FOODWEB,
    q:`Using the food web in the figure, name one organism that is a producer.`,
    a:`Grass`,
    e:`Producer là sinh vật tự tạo thức ăn bằng quang hợp — trong hình là grass và pondweed (nêu một trong hai là đúng). Mọi mũi tên năng lượng đều bắt đầu từ chúng. Owl, snake, frog, mouse là consumers vì phải ăn sinh vật khác.` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Passage", year:9, exam:true, p:BIX_FOODWEB,
    q:`Using the figure, name one organism that is prey to the owl.`,
    a:`The mouse`,
    e:`Mũi tên đi từ mouse tới owl, nghĩa là cú ăn chuột — vậy mouse là prey (con mồi) của owl. Đề thi thật yêu cầu đọc chiều mũi tên: mũi tên luôn chỉ về phía sinh vật ăn (predator).` },
  { s:"Biology", topic:"5. Farming and ecosystems", sub:"Passage", year:9, exam:true, p:BIX_FOODWEB,
    q:`The passage says only about 10 percent of energy moves to the next level. In what two main forms is most of the rest lost?`,
    a:`As heat and through movement`,
    e:`Đáp án: phần lớn năng lượng bị mất dưới dạng nhiệt (heat) và qua vận động (movement). Lý do chỉ ~10% năng lượng truyền lên bậc dinh dưỡng kế tiếp: ở mỗi bậc, sinh vật dùng phần lớn năng lượng cho hô hấp (respiration) — năng lượng này thoát ra thành nhiệt và được dùng để di chuyển. Đó là lý do food chain hiếm khi có quá 4-5 bậc.` }
);

/* ===== CHAPTER 6: Health and disease ===== */
const BIX_VIRUS = { title:`The structure of a virus`, html:`<p>A virus is an extremely tiny particle that can cause disease. It is not classed as a living organism because it cannot carry out life processes on its own and has no cells. A virus is built from an outer protein coat, called the capsid, which surrounds a small amount of genetic material known as nucleic acid. To reproduce, a virus must enter a living host cell and make that cell copy the virus many times. Influenza, which causes flu, is one well-known type of virus.</p><p><i>[Figure: a single influenza virus drawn as a rounded particle. The outer layer is labelled 'capsid (protein coat)'. The coiled thread inside the particle is labelled 'nucleic acid (genetic material)'. Short spikes stick out from the surface of the capsid.]</i></p>` };

window.QBANK.push(
  { s:"Biology", topic:"6. Health and disease", sub:"Definitions", year:9, exam:true,
    q:`What name is given to something that makes you ill, such as infection by a pathogen or a poor diet?`,
    a:`A disease`,
    e:`Disease = bệnh. Đó là điều khiến cơ thể bị ốm. Bệnh có nhiều nguyên nhân: vi sinh vật gây bệnh, thiếu chất, lỗi gene, lối sống không lành mạnh...` },
  { s:"Biology", topic:"6. Health and disease", sub:"Pathogens", year:9, exam:true,
    q:`What name is given to a microbe (microorganism) that causes disease?`,
    a:`A pathogen`,
    e:`Pathogen = mầm bệnh. Đó là vi sinh vật gây bệnh, ví dụ virus polio, vi khuẩn cholera, nấm mốc. Bệnh do pathogen gây ra gọi là bệnh truyền nhiễm.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Communicable disease", year:9, exam:true,
    q:`What name is given to a disease that can be passed from an infected person to an uninfected person?`,
    a:`A communicable disease`,
    e:`Communicable disease = bệnh truyền nhiễm. Mầm bệnh có thể lây từ người này sang người khác. Ví dụ: cúm, thuỷ đậu, dịch tả. Còn gọi là infectious disease — đáp án này cũng được chấp nhận.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Non-communicable disease", year:9, exam:true,
    q:`Give one example of a non-communicable disease.`,
    a:`Lung cancer`,
    e:`Non-communicable disease = bệnh không lây. Nó không truyền từ người sang người. Ví dụ: ung thư phổi, bệnh tim mạch, bệnh di truyền (sickle cell), tiểu đường type 1 — nêu bất kỳ một ví dụ nào.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Deficiency disease", year:9, exam:true,
    q:`What causes a deficiency disease?`,
    a:`A lack of a nutrient the body needs.`,
    e:`Deficiency disease = bệnh thiếu chất. Nó do thiếu một chất dinh dưỡng (nutrient) cần cho sự phát triển khoẻ mạnh. Ví dụ: scurvy (thiếu vitamin C), rickets, anaemia.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Disease types", year:9, exam:true,
    q:`What type of disease is caused by a fault in the DNA of a cell?`,
    a:`A genetic disease`,
    e:`Bệnh di truyền (genetic disease, còn gọi là inherited disease) do một lỗi trong DNA của tế bào. Ví dụ: sickle cell disease, haemophilia. Người sinh ra đã mang sẵn lỗi gene này.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Lifestyle disease", year:9, exam:true,
    q:`Name one factor in the way we live that can increase the risk of a lifestyle disease.`,
    a:`Smoking tobacco`,
    e:`Lifestyle disease = bệnh do lối sống. Các yếu tố như hút thuốc, ăn uống không lành mạnh, ít vận động làm tăng nguy cơ mắc bệnh tim mạch, ung thư phổi — nêu bất kỳ một yếu tố nào.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Symptoms", year:9, exam:true,
    q:`What name is given to a change in the way the body works when it is affected by a disease?`,
    a:`A symptom`,
    e:`Symptom = triệu chứng. Đó là dấu hiệu cho thấy cơ thể bị bệnh, ví dụ sốt cao hoặc nổi mẩn. Bác sĩ dựa vào triệu chứng để chẩn đoán bệnh.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Viruses", year:9, exam:true,
    q:`Viruses are not classed as living organisms. What basic unit of life do viruses NOT have?`,
    a:`Cells`,
    e:`Đáp án là tế bào (cells) — virus không có cells. Lý do virus không được coi là sinh vật sống: nó không có tế bào và không thể tự thực hiện các quá trình sống (life processes) một mình. Virus chỉ là một hạt gồm vỏ protein bọc vật chất di truyền, và chỉ nhân lên (replicate) được khi xâm nhập vào tế bào chủ (host cell).` },
  { s:"Biology", topic:"6. Health and disease", sub:"Viruses", year:9, exam:true,
    q:`What does the outer protein coat of a virus surround?`,
    a:`Genetic material`,
    e:`Đáp án: lớp vỏ protein bên ngoài của virus bao quanh vật chất di truyền (genetic material). Cấu tạo của virus rất đơn giản — chỉ gồm một lớp vỏ protein (gọi là capsid) bọc lấy vật chất di truyền bên trong; nó không có tế bào và không có bào quan như sinh vật sống.` },
  { s:"Biology", topic:"6. Health and disease", sub:"White blood cells", year:9, exam:true,
    q:`Which type of blood cell helps to destroy pathogens that get into the body?`,
    a:`White blood cells`,
    e:`Bạch cầu (white blood cells) là tế bào bảo vệ cơ thể, tiêu diệt mầm bệnh. Có hai loại quan trọng: phagocytes (nuốt mầm bệnh) và lymphocytes (tạo kháng thể).` },
  { s:"Biology", topic:"6. Health and disease", sub:"White blood cells", year:9, exam:true,
    q:`What does a phagocyte do to a pathogen?`,
    a:`It ingests the pathogen — surrounds and digests it.`,
    e:`Phagocyte là loại bạch cầu nuốt (ingest) mầm bệnh: nó bao quanh rồi tiêu hoá mầm bệnh. "Phago-" có nghĩa là "ăn".` },
  { s:"Biology", topic:"6. Health and disease", sub:"Antibodies", year:9, exam:true,
    q:`What name is given to the proteins that stick to pathogens, and which cells make them?`,
    a:`Antibodies; they are made by lymphocytes.`,
    e:`Antibodies = kháng thể, là protein bám vào mầm bệnh. Chúng do lymphocytes (một loại bạch cầu) tạo ra. Kháng thể giúp mầm bệnh dễ bị nuốt, dính lại với nhau hoặc vỡ ra.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Antibodies", year:9, exam:true,
    q:`What does it mean to say that antibodies are 'specific' for a certain pathogen?`,
    a:`Each antibody fits only one type of pathogen.`,
    e:`Mỗi mầm bệnh có bề mặt riêng, nên cần một loại kháng thể riêng vừa khít với nó — giống chìa khoá và ổ khoá. Đó là ý nghĩa của từ "specific" (đặc hiệu).` },
  { s:"Biology", topic:"6. Health and disease", sub:"Immunity", year:9, exam:true,
    q:`What does it mean if you are immune to a disease?`,
    a:`Your body can destroy the pathogen before it makes you ill.`,
    e:`Immune = miễn dịch. Khi đã miễn dịch, bạch cầu (white blood cells) của em tiêu diệt mầm bệnh rất nhanh sau khi nhiễm, nên em không bị ốm. Đó là lý do nhiều bệnh như sởi em chỉ mắc một lần.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Memory cells", year:9, exam:true,
    q:`What is the role of memory cells after an infection?`,
    a:`They make the correct antibodies quickly if the pathogen returns.`,
    e:`Memory cells là loại lymphocyte ở lại sau khi khỏi bệnh, luôn sẵn sàng. Lần sau nếu cùng mầm bệnh quay lại, chúng tạo kháng thể đúng rất nhanh và nhiều — nên em không bị ốm nữa.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Vaccines", year:9, exam:true,
    q:`What does a vaccine contain that makes the body produce antibodies and memory cells?`,
    a:`Harmless parts of a pathogen`,
    e:`Đáp án: vaccine chứa các phần vô hại của mầm bệnh (harmless parts of a pathogen) — thường là phần bề mặt (surface coating). Cách vắc-xin tạo miễn dịch: khi tiêm vào, các phần này khiến lymphocytes tạo ra kháng thể (antibodies) và memory cells để chống lại mầm bệnh. Nhờ đó em có miễn dịch (immune) mà không phải bị bệnh thật — nếu mầm bệnh thật xâm nhập sau này, cơ thể đã sẵn sàng tiêu diệt nó nhanh chóng.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Treating disease", year:9, exam:true,
    q:`What name is given to a drug that is used to treat or prevent disease?`,
    a:`A medicine`,
    e:`Đáp án là medicine (thuốc chữa bệnh). Phân biệt drug và medicine: drug là bất kỳ chất nào tác động lên cách cơ thể hoạt động (nghĩa rộng); medicine là một loại drug được dùng riêng để điều trị hoặc phòng bệnh. Vì vậy mọi medicine đều là drug, nhưng không phải drug nào cũng là medicine.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Antibiotics", year:9, exam:true,
    q:`What type of infection is an antibiotic used to treat?`,
    a:`Bacterial infections`,
    e:`Antibiotic = kháng sinh. Nó giúp cơ thể khỏi bệnh do vi khuẩn (bacterial infections) bằng cách tiêu diệt vi khuẩn. Lưu ý: kháng sinh KHÔNG có tác dụng với virus.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Antibiotics", year:9, exam:true,
    q:`Antibiotics cannot treat diseases such as flu or Ebola. What type of pathogen causes these two diseases?`,
    a:`Viruses`,
    e:`Đáp án: cúm và Ebola do virus gây ra. Lý do kháng sinh không chữa được chúng: antibiotics chỉ tiêu diệt vi khuẩn (bacteria), hoàn toàn không diệt được virus. Với bệnh do virus, ta cần thuốc kháng virus (antivirals) hoặc vắc-xin để phòng ngừa.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Antivirals", year:9, exam:true,
    q:`Antiviral medicines treat a viral disease by stopping the virus from doing what?`,
    a:`Replicating`,
    e:`Đáp án: thuốc kháng virus ngăn virus nhân lên (replicating = tự tạo ra bản sao của chính nó). Cách antiviral medicines giúp chữa bệnh do virus: vì virus chỉ có thể nhân lên bên trong tế bào chủ, nên chặn quá trình replication làm số virus không tăng được, giúp cơ thể kiểm soát và đẩy lùi bệnh.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Pandemic", year:9, exam:true,
    q:`What name is given to an infectious disease that spreads to many people in more than one country in a short time?`,
    a:`A pandemic`,
    e:`Pandemic = đại dịch. Đó là bệnh truyền nhiễm lan rộng tới nhiều người ở nhiều quốc gia trong thời gian ngắn. SARS năm 2002 lan tới 37 nước là một ví dụ.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Pandemic", year:9, exam:true,
    q:`Isolating infected people helps prevent a pandemic. What does isolation stop the pathogen from doing?`,
    a:`Being passed on to other people`,
    e:`Đáp án: cách ly ngăn mầm bệnh lây sang người khác (being passed on to other people). Lý do isolation giúp phòng đại dịch: khi người nhiễm bệnh được tách riêng, mầm bệnh không có cơ hội truyền cho người chưa nhiễm, nên dịch không lan rộng. SARS đã được kiểm soát chính nhờ cách ly người bệnh và những người từng tiếp xúc.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Transgenic organisms", year:9, exam:true,
    q:`What does the word 'transgenic' mean?`,
    a:`An organism that contains DNA from more than one species.`,
    e:`Transgenic = chuyển gene. Sinh vật transgenic mang DNA từ nhiều hơn một loài. Ví dụ: vi khuẩn được đưa gene người vào để sản xuất hormone insulin.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Transgenic organisms", year:9, exam:true,
    q:`Which type of organism is used to produce protein hormones such as insulin today?`,
    a:`Genetically modified bacteria`,
    e:`Đáp án: vi khuẩn biến đổi gene (genetically modified / transgenic bacteria). Cách insulin được sản xuất ngày nay: gene tạo hormone được lấy từ nhiễm sắc thể người và đưa vào DNA của vi khuẩn; những vi khuẩn này sau đó được nuôi với số lượng lớn trong bồn lên men (fermenter), nơi chúng tạo ra hormone insulin.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Hygiene", year:9, exam:true,
    q:`What name is given to keeping things clean to reduce the spread of pathogens?`,
    a:`Hygiene`,
    e:`Đáp án là hygiene (vệ sinh). Hygiene là việc giữ sạch sẽ và diệt vi sinh vật (microorganisms). Lý do nó giúp phòng bệnh: khi môi trường, tay và thực phẩm sạch sẽ, mầm bệnh có ít cơ hội tồn tại và lây lan hơn. Ví dụ: giữ nước uống tách biệt với nước thải đã giúp giảm mạnh bệnh tả và thương hàn.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Applied", year:9, exam:true,
    q:`Nam catches chickenpox once and never gets it again. What name is given to the cells that protect him if the virus returns?`,
    a:`Memory cells`,
    e:`Đáp án là memory cells (tế bào nhớ). Lý do Nam không mắc thuỷ đậu lần hai: sau lần nhiễm đầu tiên, cơ thể Nam giữ lại memory cells — một loại lymphocyte. Lần sau nếu cùng virus quay lại, các tế bào này nhận ra nó và tạo kháng thể đúng cực nhanh, tiêu diệt virus trước khi gây bệnh. Nam đã miễn dịch (immune) với thuỷ đậu.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Applied", year:9, exam:true,
    q:`Lan's doctor gives her an antibiotic for an ear infection but not for her flu. What type of pathogen causes the ear infection?`,
    a:`Bacteria`,
    e:`Đáp án: nhiễm trùng tai của Lan do vi khuẩn (bacteria) gây ra. Lý do bác sĩ kê kháng sinh cho tai nhưng không kê cho cúm: kháng sinh chỉ tiêu diệt vi khuẩn, nên có tác dụng với nhiễm trùng tai do vi khuẩn; còn cúm do virus (viral) gây ra mà kháng sinh không diệt được virus, nên kê kháng sinh cho cúm là vô ích.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Passage", year:9, exam:true, p:BIX_VIRUS,
    q:`Using the passage and the figure, what name is given to the outer protein coat of a virus?`,
    a:`The capsid`,
    e:`Đoạn văn và hình đều ghi rõ: lớp vỏ protein bên ngoài virus gọi là capsid. Nó bao bọc và bảo vệ vật chất di truyền bên trong. Đề thi thật 2025-2026 có hình virus với label kiểu này.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Passage", year:9, exam:true, p:BIX_VIRUS,
    q:`Using the figure, what name is given to the genetic material found inside the capsid?`,
    a:`Nucleic acid`,
    e:`Sợi cuộn bên trong capsid được dán nhãn 'nucleic acid (genetic material)'. Đó là vật chất di truyền của virus. Đề thật từng hỏi "two letter codes" cho nucleic acid — đáp án thường là DNA hoặc RNA.` },
  { s:"Biology", topic:"6. Health and disease", sub:"Passage", year:9, exam:true, p:BIX_VIRUS,
    q:`The figure shows an influenza virus. Antibiotics only kill bacteria, so what type of medicine would be used against the flu instead?`,
    a:`An antiviral`,
    e:`Đáp án là thuốc kháng virus (an antiviral). Lý do bác sĩ không kê kháng sinh cho cúm: influenza (cúm) do virus gây ra, mà kháng sinh chỉ tiêu diệt vi khuẩn — hoàn toàn không có tác dụng với virus. Vì vậy bệnh do virus cần dùng antiviral (thuốc ngăn virus nhân lên) hoặc phòng bằng vắc-xin.` }
);

/* ===== CHAPTER 7: Control, ecology and exchange ===== */
const BIX_CARBON = { title:`The carbon cycle and decomposers`, html:`<p>The carbon cycle is a model that shows how carbon atoms are recycled between living things and the air. Green plants take in carbon dioxide from the atmosphere during photosynthesis and lock the carbon into substances such as glucose and starch. The carbon passes to animals when they eat plants. Both plants and animals return carbon dioxide to the air through respiration, and burning fuels also releases it. When organisms die, decomposers such as bacteria and fungi feed on their remains, breaking them down and releasing carbon dioxide back into the air.</p><p><i>[Figure: a cycle diagram. An arrow labelled 'photosynthesis' points from the air into a plant. An arrow labelled 'feeding' points from the plant to an animal. Arrows labelled 'respiration' point from both the plant and the animal back to the air. A dead leaf and a dead animal point to a group of mushrooms and bacteria labelled 'decomposers', and an arrow returns from the decomposers to the air.]</i></p>` };
const BIX_CELLEX = { title:`Cells and exchange with the surroundings`, html:`<p>Every cell must exchange substances with its surroundings. Useful substances such as oxygen and dissolved food must move in, while waste substances such as carbon dioxide must move out. Many of these substances move by diffusion, which is the spreading of particles from where they are more crowded to where they are less crowded. Exchange happens across the surface of a cell, so the surface area to volume ratio matters. Small cells and tiny organisms have a large surface area to volume ratio, so diffusion alone is fast enough. Large animals have a small ratio, so they need special exchange organs with very large surfaces.</p><p><i>[Figure: two cubes side by side. A small cube of side 1 cm is labelled 'large surface area to volume ratio'. A large cube of side 3 cm is labelled 'small surface area to volume ratio'. Arrows show oxygen diffusing into each cube and carbon dioxide diffusing out.]</i></p>` };

window.QBANK.push(
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Nervous system", year:9, exam:true,
    q:`What is the job of the nervous system?`,
    a:`It senses changes and lets the body respond rapidly to them.`,
    e:`Nervous system = hệ thần kinh. Nó giúp ta cảm nhận thay đổi cả bên trong lẫn bên ngoài cơ thể, rồi phản ứng nhanh. Đây là hệ phản ứng nhanh của cơ thể.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Nervous system", year:9, exam:true,
    q:`Which two organs make up the central nervous system (CNS)?`,
    a:`The brain and the spinal cord`,
    e:`Central nervous system (CNS) = hệ thần kinh trung ương, gồm não (brain) và tuỷ sống (spinal cord). Các dây thần kinh (nerves) nối CNS với phần còn lại của cơ thể.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Stimuli", year:9, exam:true,
    q:`What name is given to a change inside or outside the body that the body detects and responds to?`,
    a:`A stimulus`,
    e:`Stimulus (số nhiều: stimuli) = kích thích. Đó là một thay đổi mà cơ thể nhận biết và phản ứng lại, ví dụ ánh sáng, âm thanh, nhiệt độ, cảm giác chạm.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Receptors", year:9, exam:true,
    q:`What name is given to cells that detect stimuli, such as cells in the eye that detect light?`,
    a:`Receptor cells`,
    e:`Receptor cells = tế bào thụ cảm. Chúng phát hiện kích thích và nằm trong các sense organs (cơ quan cảm giác) như mắt, tai, da. Khi phát hiện kích thích, chúng tạo ra xung thần kinh.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Impulses", year:9, exam:true,
    q:`What name is given to the electrical signals that travel along nerves?`,
    a:`Impulses`,
    e:`Impulses = xung thần kinh, là các tín hiệu điện chạy dọc dây thần kinh. Tế bào thụ cảm tạo xung khi phát hiện kích thích; xung truyền tới não qua tuỷ sống.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Effectors", year:9, exam:true,
    q:`What name is given to organs that bring about responses, such as muscles and glands?`,
    a:`Effectors`,
    e:`Effectors = cơ quan đáp ứng. Đó là cơ quan thực hiện phản ứng: cơ (muscles) thì co lại, tuyến (glands) thì tiết hormone. Não gửi xung tới effectors để tạo phản ứng.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Hormones", year:9, exam:true,
    q:`What name is given to a chemical messenger released from a gland into the blood and carried around the body?`,
    a:`A hormone`,
    e:`Hormone = chất truyền tin hoá học. Nó được tuyến (gland) tiết vào máu và đi khắp cơ thể. Các target cells/organs đáp ứng bằng cách thay đổi hoạt động của chúng.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Hormones", year:9, exam:true,
    q:`Which gland releases the hormone insulin, and what does insulin do?`,
    a:`The pancreas; insulin makes cells take up glucose from the blood.`,
    e:`Tuyến tuỵ (pancreas) tiết insulin. Insulin làm tế bào cơ (muscle) và gan (liver) hấp thụ glucose từ máu, giúp giảm đường huyết. Trong tiểu đường type 1, mô tạo insulin bị phá huỷ.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Hormones", year:9, exam:true,
    q:`Which hormone increases the heart rate and breathing rate?`,
    a:`Adrenaline`,
    e:`Adrenaline do tuyến thượng thận (adrenal gland) tiết ra. Khi gặp nguy hiểm, nó làm tim đập nhanh và thở nhanh hơn — chuẩn bị cho cơ thể "chiến đấu hoặc bỏ chạy".` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Comparing systems", year:9, exam:true,
    q:`Which control system gives a faster response: the nervous system or the hormonal system?`,
    a:`The nervous system`,
    e:`Đáp án: hệ thần kinh (the nervous system) cho phản ứng nhanh hơn. So sánh hai hệ điều khiển: hệ thần kinh phản ứng nhanh và ngắn, dùng xung điện truyền dọc dây thần kinh; hệ hormone phản ứng chậm hơn nhưng kéo dài hơn, dùng chất hoá học (hormone) đi trong máu và có thể tác động lên nhiều cơ quan cùng lúc.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Abundance", year:9, exam:true,
    q:`What name is given to how common a species is in a habitat or ecosystem?`,
    a:`Abundance`,
    e:`Abundance = độ phong phú = mức độ phổ biến của một loài trong nơi ở. Nó còn gọi là population size (kích thước quần thể).` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Population", year:9, exam:true,
    q:`What name is given to the number of a certain organism found in a certain area?`,
    a:`A population`,
    e:`Population = quần thể = số lượng cá thể của một loài trong một khu vực. Vì hiếm khi đếm được hết, các nhà khoa học lấy mẫu (samples) để ước lượng.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Sampling", year:9, exam:true,
    q:`When scientists cannot count every organism, what do they take to estimate a population size?`,
    a:`Samples`,
    e:`Đáp án là các mẫu (samples). Lý do nhà khoa học lấy mẫu thay vì đếm hết: tìm và đếm mọi cá thể trong một khu vực thường là không thể — quá tốn thời gian và nhiều sinh vật khó thấy. Vì vậy họ đếm trong vài mẫu nhỏ (samples), ví dụ bằng quadrat, rồi nhân lên để ước lượng (estimate) tổng quần thể.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Distribution", year:9, exam:true,
    q:`What is meant by the distribution of organisms?`,
    a:`How the organisms are spread out throughout an area.`,
    e:`Distribution = sự phân bố = cách các sinh vật trải ra trong khu vực. Ba kiểu chính: random (ngẫu nhiên), regular (đều) và clumped (tụ thành cụm).` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Distribution", year:9, exam:true,
    q:`What name is given to a survey where scientists sample organisms along a line or belt?`,
    a:`A transect survey`,
    e:`Transect survey = khảo sát theo tuyến. Nhà khoa học lấy mẫu dọc theo một đường thẳng. Nếu phân bố đều, loài xuất hiện ở mọi mẫu; nếu tụ cụm, chỉ ở vài mẫu.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"SA:V ratio", year:9, exam:true,
    q:`What does SA:V ratio stand for?`,
    a:`Surface area to volume ratio`,
    e:`SA:V ratio = tỉ lệ diện tích bề mặt trên thể tích. Tính bằng: diện tích bề mặt chia cho thể tích. Tỉ lệ này càng lớn thì vật có càng nhiều bề mặt so với mỗi đơn vị thể tích.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"SA:V ratio", year:9, exam:true,
    q:`Calculate the surface area to volume ratio of a cube with sides of 2 cm. Give your answer as a single number.`,
    a:`3`,
    e:`Diện tích bề mặt = 6 mặt × (2×2) = 24 cm². Thể tích = 2×2×2 = 8 cm³. SA:V = 24 ÷ 8 = 3. Vật càng nhỏ thì tỉ lệ SA:V càng lớn.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"SA:V ratio", year:9, exam:true,
    q:`Small animals cool down faster than large animals. Compared with large animals, is their SA:V ratio larger or smaller?`,
    a:`Larger`,
    e:`Đáp án: động vật nhỏ có tỉ lệ SA:V lớn hơn (larger). Lý do động vật nhỏ nguội đi nhanh hơn: tỉ lệ SA:V lớn nghĩa là chúng có nhiều bề mặt so với mỗi đơn vị thể tích, mà nhiệt thoát ra qua bề mặt — nên với thể tích nhỏ, chúng mất nhiệt nhanh hơn nhiều so với động vật lớn (vốn có SA:V nhỏ).` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"SA:V ratio", year:9, exam:true,
    q:`Large organisms need organs such as lungs because their SA:V ratio is too small for which process to supply every cell?`,
    a:`Diffusion`,
    e:`Đáp án là khuếch tán (diffusion). Lý do sinh vật lớn cần cơ quan có bề mặt lớn: chúng có SA:V ratio nhỏ — quá ít bề mặt ngoài so với thể tích, nên diffusion qua bề mặt cơ thể không đủ nhanh để cung cấp oxygen và thức ăn cho mọi tế bào bên trong. Vì vậy chúng cần các cơ quan trao đổi có bề mặt rất lớn (như phổi, ruột non) để hấp thụ chất đủ nhanh.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Diffusion", year:9, exam:true,
    q:`What name is given to the spreading and mixing of particles without anything moving them?`,
    a:`Diffusion`,
    e:`Diffusion = sự khuếch tán. Các hạt tự lan từ nơi đông sang nơi thưa. Diffusion nhanh hơn ở nhiệt độ cao và khi chênh lệch nồng độ lớn. Khí vào/ra tế bào qua khuếch tán.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Osmosis", year:9, exam:true,
    q:`What name is given to the overall movement of water molecules through a partially permeable membrane?`,
    a:`Osmosis`,
    e:`Osmosis = thẩm thấu = một dạng khuếch tán. Đó là sự di chuyển tổng thể của nước qua màng bán thấm — từ nơi có nhiều phân tử nước sang nơi có ít hơn.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Osmosis", year:9, exam:true,
    q:`What is a partially permeable membrane?`,
    a:`A membrane that lets some particles cross through it but not others.`,
    e:`Màng bán thấm (partially permeable membrane) chỉ cho một số phân tử nhỏ đi qua, chặn các phân tử khác. Màng tế bào là một ví dụ — osmosis xảy ra qua loại màng này.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Enzymes", year:9, exam:true,
    q:`What name is given to a substance that speeds up reactions in living things, such as breaking down food molecules?`,
    a:`An enzyme`,
    e:`Enzyme = chất xúc tác sinh học. Nó tăng tốc các phản ứng trong cơ thể mà bản thân không bị biến đổi. Mọi enzyme đều là protein. Nhiều enzyme phân giải phân tử lớn thành phân tử nhỏ.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Villi", year:9, exam:true,
    q:`What do the villi in the small intestine greatly increase, making them well adapted for absorbing digested food?`,
    a:`The surface area`,
    e:`Đáp án: diện tích bề mặt (the surface area). Cách villi thích nghi với việc hấp thụ thức ăn: villi (số ít: villus) là vô số nếp nhỏ hình ngón tay phủ thành trong ruột non; chúng làm tăng diện tích bề mặt lên rất nhiều, nhờ đó thức ăn đã tiêu hoá được hấp thụ vào máu nhanh hơn hẳn so với một bề mặt phẳng.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Applied", year:9, exam:true,
    q:`Nam treads on a sharp object and quickly lifts his foot. Which control system is responsible for this fast response?`,
    a:`The nervous system`,
    e:`Hệ thần kinh chịu trách nhiệm cho phản ứng nhanh này, vì nó truyền xung điện rất nhanh. Hệ hormone phản ứng chậm hơn nhiều, không phù hợp với tình huống cấp bách.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Applied", year:9, exam:true,
    q:`Mai finds 4 crabs in a 0.5 m × 0.5 m quadrat. The whole rocky area is 100 m². Estimate the total crab population.`,
    a:`1600 crabs`,
    e:`Diện tích mẫu = 0.5 × 0.5 = 0.25 m². Số lần mẫu vừa khu vực = 100 ÷ 0.25 = 400. Tổng quần thể ≈ 4 × 400 = 1600 con cua. Đây là cách ước lượng population size từ mẫu.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Applied", year:9, exam:true,
    q:`Lan sees adrenaline being released when a person is frightened. What happens to the heart rate and breathing rate?`,
    a:`They increase.`,
    e:`Đáp án: nhịp tim và nhịp thở đều tăng lên (they increase). Cách adrenaline chuẩn bị cho cơ thể đối mặt nguy hiểm: khi tim đập nhanh hơn và thở nhanh hơn, máu mang nhiều oxygen và glucose hơn tới các cơ. Nhờ đó cơ có đủ năng lượng để cơ thể sẵn sàng "chiến đấu hoặc bỏ chạy" (fight or flight) khi gặp nguy hiểm.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Passage", year:9, exam:true, p:BIX_CARBON,
    q:`Using the passage and the figure, what name is given to organisms such as bacteria and fungi that break down dead remains?`,
    a:`Decomposers`,
    e:`Vi khuẩn và nấm phân huỷ xác chết được gọi là decomposers (sinh vật phân huỷ). Hình minh hoạ dán nhãn nhóm nấm là 'decomposers'. Chúng trả CO₂ về không khí, khép kín carbon cycle.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Passage", year:9, exam:true, p:BIX_CARBON,
    q:`Using the passage, name the one process in the carbon cycle that removes carbon dioxide from the air.`,
    a:`Photosynthesis`,
    e:`Trong chu trình carbon, chỉ photosynthesis (quang hợp) lấy CO₂ ra khỏi không khí. Các quá trình khác — respiration, combustion, decomposition — đều thải CO₂ trở lại không khí.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Passage", year:9, exam:true, p:BIX_CARBON,
    q:`To which group in the carbon cycle do mushrooms and earthworms belong?`,
    a:`Decomposers`,
    e:`Đáp án: nấm và giun đất là decomposers (sinh vật phân huỷ). Cách chúng trả carbon về không khí: khi ăn và phân huỷ xác chết (dead remains), decomposers thực hiện hô hấp (respiration) và thải khí CO₂ trở lại không khí. Nhờ đó carbon trong cơ thể sinh vật chết được giải phóng và tái sử dụng liên tục trong carbon cycle.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Passage", year:9, exam:true, p:BIX_CELLEX,
    q:`Using the passage, what name is given to the movement of particles from where they are more crowded to where they are less crowded?`,
    a:`Diffusion`,
    e:`Đoạn văn định nghĩa: sự lan của các hạt từ nơi đông sang nơi thưa chính là diffusion (khuếch tán). Oxygen và CO₂ đi vào/ra tế bào chủ yếu nhờ diffusion qua màng tế bào.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Passage", year:9, exam:true, p:BIX_CELLEX,
    q:`Using the figure, which cube has the larger surface area to volume ratio, the 1 cm cube or the 3 cm cube?`,
    a:`The 1 cm cube`,
    e:`Khối lập phương nhỏ (cạnh 1 cm) có SA:V ratio lớn hơn — nhiều bề mặt so với thể tích. Hình ghi rõ nhãn 'large surface area to volume ratio' cho khối nhỏ. Vật càng nhỏ, tỉ lệ SA:V càng lớn.` },
  { s:"Biology", topic:"7. Control, ecology and exchange", sub:"Passage", year:9, exam:true, p:BIX_CELLEX,
    q:`Using the passage, a large animal needs special exchange organs such as lungs. Is its surface area to volume ratio large or small?`,
    a:`Small`,
    e:`Đáp án: tỉ lệ diện tích bề mặt trên thể tích của động vật lớn là nhỏ (small). Lý do nó cần cơ quan trao đổi đặc biệt: SA:V ratio nhỏ nghĩa là bề mặt ngoài quá ít so với thể tích, nên khuếch tán (diffusion) qua da không đủ nhanh để cung cấp oxygen cho mọi tế bào sâu bên trong. Vì vậy động vật lớn cần các cơ quan trao đổi có bề mặt rất lớn như phổi (lungs).` }
);
